import urllib.request, urllib.error, re
from urllib.parse import urljoin

base = 'http://localhost:5000/'
seed_paths = ['/', '/page', '/page?name=test']
assets = set()
htmls = {}
for p in seed_paths:
    with urllib.request.urlopen(urljoin(base, p), timeout=5) as r:
        html = r.read().decode('utf-8','ignore')
        htmls[p]=html
        for m in re.findall(r'\b(?:src|href)=["\']([^"\']+)["\']', html, re.I):
            assets.add(m)

print('Discovered assets:', sorted(assets))

# Fetch assets and search for flag-like patterns
flag_regex = re.compile(r'FLAG\{[^}]+\}|CTF\{[^}]+\}|flag\{[^}]+\}', re.I)

for a in sorted(assets):
    url = urljoin(base, a)
    try:
        with urllib.request.urlopen(url, timeout=5) as r:
            ct = r.headers.get('Content-Type','')
            data = r.read()
            print('\n--', a, ct, len(data))
            if 'text' in ct or 'javascript' in ct or 'json' in ct or a.endswith(('.css','.js','.html','.txt','.json')):
                text = data.decode('utf-8','ignore')
                m = flag_regex.search(text)
                if m:
                    print('FOUND FLAG IN', a, ':', m.group(0))
                else:
                    # print a snippet for manual inspection
                    snippet = '\n'.join([line for line in text.splitlines() if 'flag' in line.lower()][:10])
                    if snippet:
                        print('Mentions:', snippet)
    except urllib.error.HTTPError as e:
        print('\n--', a, 'HTTP', e.code)
    except Exception as e:
        print('\n--', a, 'ERR', e)

